export default function StatsRow() {
  const ref = useRef<HTMLDivElement>(null);
  const [animate, setAnimate] = useState(false);

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => { if (entry.isIntersecting) setAnimate(true); },
      { threshold: 0.3 }
    );
    if (ref.current) observer.observe(ref.current);
    return () => observer.disconnect();
  }, []);

  return (
    <div data-component-id="src/app/welcome-landing-screen/components/StatsRow.tsx:114:4" data-component-path="src/app/welcome-landing-screen/components/StatsRow.tsx" data-component-line="114" data-component-end-line="118" data-component-file="StatsRow.tsx" data-component-name="div" data-component-content="%7B%22elementName%22%3A%22div%22%2C%22className%22%3A%22grid%20grid-cols-2%20md%3Agrid-cols-4%20gap-4%20mb-16%22%7D" ref={ref} className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-16">
      {stats.map((stat) => (
        <StatCard data-component-id="src/app/welcome-landing-screen/components/StatsRow.tsx:116:8" data-component-path="src/app/welcome-landing-screen/components/StatsRow.tsx" data-component-line="116" data-component-end-line="116" data-component-file="StatsRow.tsx" data-component-name="StatCard" data-component-content="%7B%22elementName%22%3A%22StatCard%22%7D" key={stat.id} stat={stat} animate={animate} />
      ))}
    </div>
  );
}